import{_ as p,o as e,c as a,j as r,a as n,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const u=JSON.parse('{"title":"饿鬼流","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/肉搏类/无暇武道/饿鬼流.md","filePath":"4.资源分区/6.技艺及称号/武技类/肉搏类/无暇武道/饿鬼流.md"}'),t={name:"4.资源分区/6.技艺及称号/武技类/肉搏类/无暇武道/饿鬼流.md"};function d(s,b,i,l,h,c){return e(),a("div",null,[...b[0]||(b[0]=[r("h1",{id:"饿鬼流",tabindex:"-1"},[n("饿鬼流 "),r("a",{class:"header-anchor",href:"#饿鬼流","aria-label":'Permalink to "饿鬼流"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：绯红庆典040")])])],-1),o('<h1 id="饿鬼流-1" tabindex="-1">饿鬼流 <a class="header-anchor" href="#饿鬼流-1" aria-label="Permalink to &quot;饿鬼流&quot;">​</a></h1><p>饿鬼流</p><p>本流派的起源大多指向某个村庄、城市或寺庙被活死人淹没的故事。那些没有受到过战斗和武术训练的少数幸存者们通过唯一的老师——饿鬼狩猎活物的行动来学习战斗。尽管此类故事的真实性存在一定争议，但在尘世许多地区都可以找到本流派的变体，这类地区的生者居民通常畏惧着死者，比如阴阳界闹鬼地区、白墙周围的定居点或是无间最底层区域。</p><p>这种流派强调锻炼肉体，通过爆发的速度驱动有力的打击，对学徒精神层面的训练相比之下较为失色。学徒们一般需要冥想自己最强烈、原始的激情，从内心深处酝酿力量，在战斗中进入饥渴疯狂的状态。那些不了解此流派的人看到饿鬼流武者的战斗方式可能会把他们误认为真的是怪物。（普通人看到的大概率是真的怪物，少部分情况则两者皆是）</p><p>饿鬼流武器：这种流派的徒手战斗服从于原始的激情，因此可以适用于任何天生武器，包括且不限于爪，牙甚至是头槌。本流派的肉搏攻击都造成严重而不再是冲击。本流派也兼容手斧、手镰和虎爪。</p><p>盔甲：兼容所有护甲。</p><p>手镰：单手使用的短柄镰刀。用于田间地头割草收麦的款式，不包括长柄巨镰。</p><p>嗜血饥渴（Blood-Scenting Hunger）<br> 价格：D+500<br> 购买前提：武技3+<br> 类型：被动<br> 持续时间：立即<br> 前置秘法：无<br> 武者从空气中探寻猎物的气息，被饥渴驱动。</p><p>武者在进行先攻检定时额外获得1个d10的先攻骰。武者的白刃武器/天生武器被武者的饥渴所填充，亮起血色幽光，使得武者额外获得2L武器伤害的提升。</p><p>恐惧迫近（Leaping Horror Approach）<br> 价格：D+500<br> 购买前提：武技3+<br> 类型：主动<br> 动作：移动动作<br> 持续时间：立即<br> 前置秘法：无<br> 武者的躯体充斥怒火，令其从一处尸山跃向另一处血海。</p><p>移动动作使用，武者可以在进行一次基础移动后进行一次跳跃检定，额外移动跳跃检定成功数的距离。在一这种方式迫近敌人时，若对方同样处于落点附近的地面上（也就是说，跳起来打浮空的敌人无法触发），则武者迅猛沉重的下落所带来的冲击，将使得武者本轮内的下一次近战攻击，额外获得4dp力量检定上的增强加值。</p><p>饿鬼咠噬（Roaring Devour）<br> 价格：C+1500<br> 购买前提：运动3+<br> 类型：被动<br> 持续时间：立即<br> 前置秘法：无<br> 饿鬼咠噬祭品时刻已到，咠祭五脏，通达天地。</p><p>仅对于一名被武者所【杀死】的，具有血肉单位而言，武者可将其视为咠祭品，在战都后将其尸身尽数吞噬，血肉，骨骼，皮毛，内脏乃至灵魂，都吞入腹中，而武者的肚子此时也将庞大到臃肿的地步，此时，该单位无法被A级及以下的复活能力所复活。<br> 对于吞入腹中的血食，武者可以花费15分钟将其尽数消化，化为驱动这可怖身躯的燃料，如此做后，武者视为满足了今日的饮食所需，若目标为同级别单位的尸体，则武者的力量检定永久获得2dp增强加值。<br> 武者一影片内，通过咠噬获得力量检定增强加值的机会仅生效一次。</p><p>铁墓之囚（Iron Tomb Imprisonment）<br> 价格：C+1000<br> 购买前提：运动3+<br> 类型：被动<br> 持续时间：立即<br> 前置秘法：无<br> 灵体铆钉将武者的盔甲钉入他的血肉，灵质链条缠绕在四周，将其捆束。</p><p>武者将自己封印在盔甲中，使得盔甲如同武者肉体的延伸，血腥的长钉和锈迹斑斑的铁链将铠甲永久的铆钉在武者的血肉身躯之上-—除非回到主神空间借助主神伟力，否则武者自己都无法将其脱下。<br> 。<br> 该状态下，武者所穿的铠甲将自动获得【免疫接触攻击】特性，并额外获得基于盔甲防御的1点全伤害吸收和2点基于该技艺所选盔甲的盔甲防御。</p><p>怪诞蠕行(Unnatural Shambling Deftness)<br> 价格：750<br> 购买前提：武技3+<br> 类型：主动<br> 动作：移动<br> 持续时间：无限<br> 前置秘法：无<br> 武者在战场上穿行，时而如饿鬼般蹒跚，时而爆发出非人的速度。</p><p>武者的关节，颈椎可以在武者的控制下，做到近乎360度的旋转，这允许武者以移动动作，做出怪诞而可怖的姿势，手脚反弓，脖子扭转的在地面上爬行。此时，武者视为进入类【伏地】状态。<br> -类【伏地】状态下，武者的形象可怖而怪异，所有第一次看到或意识到武者的普通人（不具有传奇属性，也并非职业军人杀手的民众），都需要进行一个dc1的意志豁免，失败则承受1点无支线等级影响心灵来源的恐惧点数，恐惧点数不会叠加。<br> -类【伏地】状态下，武者可以全速移动，无需速度减半，且面对近战攻击也无需承受2dp减值的劣势，但依然获得对远程攻击2dp掩蔽加值。<br> 取消怪诞蠕行是一个移动动作。</p><p>饿鬼势（Hungry Ghost Form）<br> 价格：C+1000<br> 购买前提：武技4+<br> 类型：架势<br> 动作：移动动作启用/维持<br> 持续时间：饿鬼势维持期间<br> 前置秘法：怪诞蠕行(Unnatural Shambling Deftness) 恐惧迫近（Leaping Horror Approach）<br> 武者发出如野兽般的怒嚎，浑身肌肉隆起扭曲，眼放幽光，化身为饿鬼般的姿态。</p><p>武者在在进入【饿鬼势】后，自动进入【怪诞蠕行】状态，额外获得如下好处：<br> l 武者在力量属性相关检定上，获得7dp的增强加值。<br> l 武者获得血爪特性，攻击附带1点C级创伤来源的流血异常点数，强韧豁免。<br> l 武者免疫C级及以下的困难地形。<br> 每轮一次，维持饿鬼势时可以立即进行一次移动。</p><p>血肉沸腾（flesh and blood boiling）<br> 价格：C+2000<br> 购买前提：力量11+<br> 类型：被动<br> 持续时间：一场景<br> 前置秘法：饿鬼咠噬（Roaring Devour）<br> 血肉在冥渊武者的控制下扭曲翻腾，化作迅猛可怖的身形。<br> 借助秘法，武者可以更改自身的体态，将扭曲庞大的肌肉野兽，化作干枯瘦削的敏捷饿鬼。每场景一次，在进入场景时，武者可以决定在接下来的战斗场景中，使用力量代替敏捷（包括力量属性上的相关加值），来作为自己的肉搏攻击检定的构成。若如此做，则武者的肌肉将变得干枯，皮肤如同橡胶一般蜡黄紧贴骨骼，头发如水草一般紧紧贴在头上，嘴唇干裂，露出漆黑锋利的牙齿，唯有肚子不正常的突起，武者的容貌不可避免的降低为0，此时，武者的攻击将获得等同力量属性/2的增强加值。</p><p>箭步如鬼（Lunging Phantom Method）<br> 价格：C+1000<br> 购买前提：武技4+<br> 类型：主动<br> 动作：标准动作<br> 持续时间：立即<br> 前置秘法：无<br> 前置秘法：饿鬼势（Hungry Ghost Form）<br> 武者在敌人意识到他动向之前从奇诡的方位向敌人扑去。</p><p>武者进行一次攻击，若先攻顺位高于对方，该次攻击视为具有B级【措手不及】。如同武者攻击了敌人的破绽般，该次攻击将额外获得10dp速度加值。</p><p>鬼影防御（Scuttling Apparition Defense）<br> 价格：C+1000<br> 购买前提：武技5+<br> 类型：被动<br> 持续时间：一轮<br> 前置秘法：饿鬼势（Hungry Ghost Form）恐惧迫近（Leaping Horror Approach）<br> 被武者吞噬的精魂将化作永世的奴仆，为饿鬼抵挡伤害。</p><p>若武者本轮使用了使用【恐惧迫近】，且处于【饿鬼势】中，则武者在本轮中，那些武者杀死的精魂，将化作伥鬼缠绕身周，武者额外获得5点立场防御和立场防御上的2点附加成功。</p><p>殇魂突袭（Shrouded Claw Attack）<br> 价格：B+2000<br> 购买前提：武技4+<br> 类型：主动<br> 动作：-<br> 持续时间：立即<br> 前置秘法：无<br> 前置秘法：饿鬼势（Hungry Ghost Form）箭步如鬼（Lunging Phantom Method）</p><p>武者的攻击浸透了熵的精髓，腐蚀敌人的防御。</p><p>武者在使用【箭步如鬼】时，其造成的【措手不及】提升到A级，且此时攻击获得【8加骰】。武者还将无视目标的盔甲防御，这是B级时空来源的无视防御效果。</p><p>吞魔食鬼（Soul-Consuming Transcendence）<br> 价格：A+4000<br> 购买前提：武技4+<br> 类型：主动<br> 动作：-<br> 持续时间：立即<br> 前置秘法：饿鬼势（Hungry Ghost Form）殇魂突袭（Shrouded Claw Attack）饿鬼咠噬（Roaring Devour）</p><p>饥渴的饿鬼流宗师打开自己魂魄的灵性巨口吞噬敌人，惨白色的精髓弧光环绕着他旋转。</p><p>每轮一次，当武者使用【殇魂突袭】时，本次攻击造成伤害全部为韧性伤害。若受攻击单位为一名具有血肉的非构装/不死生物，且若先攻顺位高于对方且攻击命中，对方需要立即进行一次意志豁免对抗该次攻击造成的伤害，如果失败武者将立刻吞噬目标，表现为武者的口腔不自然的膨胀到巨大的程度，变为一个漆黑幽深的深渊，哪怕敌人的分量之大足可使任何生物的肚腹胀破。即使是食道无法容纳也可囫囵吞下，这是一个A级时空来源的即死效果。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',32)])])}const _=p(t,[["render",d]]);export{u as __pageData,_ as default};
